117	// a SHARED path must instantiate per-(peer,path) state (codec, remote, prober, tx/rx) for BOTH
118	// peers, and a runtime RemovePath must tear that per-(peer,path) state down for BOTH peers,
119	// leaving each peer's remaining paths untouched. It proves the fan-out has a single owner
120	// (attachSharedPathLocked / RemovePath) exercised while >=2 peerStates exist.
121	func TestMultipathSharedPathFanOutAcrossPeers(t *testing.T) {
