		return err
	}
	if schedIdx != len(m.paths)-1 {
		bindIdx := len(m.paths) - 1
		_ = dyn.RemovePath(schedIdx)
		m.paths = m.paths[:len(m.paths)-1]
		m.shared = m.shared[:len(m.shared)-1]
